  function updatePracticeTimerDisplay(){const seconds=Math.max(0,state.activePractice?.remainingSeconds||0),minutes=Math.floor(seconds/60),rest=seconds%60;$('#practiceTimer').textContent=`${String(minutes).padStart(2,'0')}:${String(rest).padStart(2,'0')}`;$('#practiceTimer').classList.toggle('urgent',seconds<=300)}
  function tickPracticeClock(){const practice=state.activePractice;if(!practice||practice.mode!=='exam'||practicePaused||reviewSession)return;const now=Date.now(),last=practice.lastTickAt?new Date(practice.lastTickAt).getTime():now,elapsed=Math.max(0,Math.floor((now-last)/1000));if(elapsed){practice.remainingSeconds=Math.max(0,practice.remainingSeconds-elapsed);practice.lastTickAt=new Date(now).toISOString();updatePracticeTimerDisplay();if(practice.remainingSeconds===0){finishPractice(true);return}if(practice.remainingSeconds%15===0)save(false)}}
